// Hidden-Screw Spiral Cone — a print-in-place NUT-AND-BOLT fidget. A smooth
// 5-start threaded cone (the "nut") fully hides a matching helical screw (the
// "bolt") inside; twist it and the screw winds out through the open base. These
// are TWO DISTINCT parts (componentCount === 2) — a real male/female thread
// pair, not a cone sliced into symmetric halves. Treat 1 unit ≈ 1 mm.
const { Manifold, CrossSection } = api;
const p = api.params({
  starts:      { type: 'int',    default: 5,   min: 3,   max: 7,   step: 1,    label: 'Thread starts' },
  baseR:       { type: 'number', default: 18,  min: 11,  max: 28,  step: 0.5,  unit: 'mm', label: 'Base radius' },
  height:      { type: 'number', default: 54,  min: 34,  max: 92,  step: 1,    unit: 'mm', label: 'Height' },
  turns:       { type: 'number', default: 2.6, min: 1.4, max: 5,   step: 0.1,  label: 'Thread turns' },
  clearance:   { type: 'number', default: 0.9, min: 0.5, max: 1.6, step: 0.05, unit: 'mm', label: 'Thread clearance' },
  threadDepth: { type: 'number', default: 0.20, min: 0.12, max: 0.32, step: 0.01, label: 'Thread depth (×R)' },
  bore:        { type: 'number', default: 0.16, min: 0,  max: 0.34, step: 0.02, label: 'Screw bore (×R)' },
});

const N = Math.round(p.starts), R = p.baseR, H = p.height;
const peakR = R * 0.6, amp = R * p.threadDepth;
const sPoint = 0.04;                       // outer cone tip sharpness (→ a point)
const Hs = H * 0.62;                        // threaded engagement height (lower body)
const rate = (360 * p.turns) / H;           // shared helix rate (deg per unit height)
const twS = rate * Hs, sS = 1 - (1 - sPoint) * Hs / H;   // screw twist + taper at Hs
const scale = 1 + p.clearance / peakR;      // mesh-dilation factor for the bore
const boreR = R * p.bore;

function lobed(crest, lobes, depth, n = 170) {
  const pts = [];
  for (let i = 0; i < n; i++) {
    const a = (i / n) * Math.PI * 2;
    const rr = crest - depth * (0.5 - 0.5 * Math.cos(lobes * a));
    pts.push([Math.cos(a) * rr, Math.sin(a) * rr]);
  }
  return CrossSection.ofPolygons([pts]);
}
const box = (w, h, z0) => Manifold.cube([w, w, h], false).translate([-w / 2, -w / 2, z0]);

// REUSABLE: split a body into a male screw + female socket along an N-start
// helical thread. Two tricks make it robust for faceted lobed profiles:
//  1. the socket bore is the SCREW'S OWN mesh scaled outward (`scale`) — same
//     facets pushed out, so the gap is collision-free by construction (two
//     independently-faceted lobed surfaces otherwise tangent-touch at any gap);
//  2. the shared build-plane edge is broken by widening the socket's base mouth,
//     and the screw's top is recessed below the bore — otherwise the parts weld
//     along those coincident faces. Returns { screw, socket }.
function screwSplit({ threadProfile, outline, Hthread, Hbody, twistThread, sThread, twistBody, sBody, scale, boreR }) {
  let screw = threadProfile.extrude(Hthread, 150, twistThread, sThread);
  if (boreR > 0.4) screw = screw.subtract(
    CrossSection.circle(boreR, 48).extrude(Hthread + 2, 80, twistThread, sThread).translate([0, 0, -1]));
  screw = screw.intersect(box(400, Hthread - 3, 0));                 // recess screw top
  const cut = threadProfile.extrude(Hthread, 150, twistThread, sThread).scale([scale, scale, 1]);
  let socket = outline.extrude(Hbody, 170, twistBody, sBody).subtract(cut);
  socket = socket.subtract(cut.scale([1.3, 1.3, 1]).intersect(box(600, 1.6, -0.01)));  // open base mouth
  return { screw, socket };
}

const { screw, socket } = screwSplit({
  threadProfile: lobed(peakR, N, amp),
  outline: lobed(R, N, R * 0.14),
  Hthread: Hs, Hbody: H,
  twistThread: twS, sThread: sS,
  twistBody: 360 * p.turns, sBody: sPoint,
  scale, boreR,
});

return api.labeledUnion([
  { name: 'screw',  shape: screw,  color: '#f5b324' },
  { name: 'socket', shape: socket, color: '#7c3aed' },
]);
